def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 7):
            term = ((-1) ** j) * (ratio ** j) / j
            if j % 2 == 0:
                term *= 1.5
            else:
                term /= 1.5
            score += term
        if capacity < item * 1.2:
            score *= 3
            for k in range(1, 4):
                score += ((-1) ** k) * (ratio ** (k+6)) / (k+6)
        elif capacity < item * 2:
            score *= 1.5
            for k in range(1, 3):
                score -= ((-1) ** (k+1)) * (ratio ** (k+3)) / (k+3)
        elif capacity > item * 4:
            score /= 3
            for k in range(1, 5):
                score += ((-1) ** k) * (ratio ** (k+8)) / (k+8)
        else:
            for k in range(1, 3):
                score += ((-1) ** (k+1)) * (ratio ** (k+5)) / (k+5)
        if ratio > 0.8:
            priorities[i] = -score * 2
        elif ratio > 0.5:
            priorities[i] = -score * 1.2
        else:
            priorities[i] = -score
    return priorities
